30	static void transfer_attr (Cell* to, const Cell* from, IdString attr) {
31		if (from->has_attribute(attr))
32			to->attributes[attr] = from->attributes.at(attr);
33	}
34	static void transfer_src (Cell* to, const Cell* from) {
35		transfer_attr(to, from, ID::src);
36	}
