38	void simplemap_not(RTLIL::Module *module, RTLIL::Cell *cell)
39	{
40		RTLIL::SigSpec sig_a = cell->getPort(ID::A);
41		RTLIL::SigSpec sig_y = cell->getPort(ID::Y);
42	
43		sig_a.extend_u0(GetSize(sig_y), cell->parameters.at(ID::A_SIGNED).as_bool());
44	
45		for (int i = 0; i < GetSize(sig_y); i++) {
46			RTLIL::Cell *gate = module->addCell(NEW_ID, ID($_NOT_));
47			transfer_src(gate, cell);
48			gate->setPort(ID::A, sig_a[i]);
49			gate->setPort(ID::Y, sig_y[i]);
50		}
51	}
