53	void simplemap_buf(RTLIL::Module *module, RTLIL::Cell *cell)
54	{
55		RTLIL::SigSpec sig_a = cell->getPort(ID::A);
56		RTLIL::SigSpec sig_y = cell->getPort(ID::Y);
57	
58		if (sig_a.has_const(State::Sz)) {
59			SigSpec new_a;
60			SigSpec new_y;
61			for (int i = 0; i < GetSize(sig_a); ++i) {
62				SigBit b = sig_a[i];
63				if (b == State::Sz)
64					continue;
65				new_a.append(b);
66				new_y.append(sig_y[i]);
67			}
68			sig_a = std::move(new_a);
69			sig_y = std::move(new_y);
70		}
71	
72		if (!sig_y.empty())
73			module->connect(RTLIL::SigSig(sig_y, sig_a));
74	}
