86	void simplemap_bitop(RTLIL::Module *module, RTLIL::Cell *cell)
87	{
88		RTLIL::SigSpec sig_a = cell->getPort(ID::A);
89		RTLIL::SigSpec sig_b = cell->getPort(ID::B);
90		RTLIL::SigSpec sig_y = cell->getPort(ID::Y);
91	
92		if (cell->type != ID($bweqx)) {
93			sig_a.extend_u0(GetSize(sig_y), cell->parameters.at(ID::A_SIGNED).as_bool());
94			sig_b.extend_u0(GetSize(sig_y), cell->parameters.at(ID::B_SIGNED).as_bool());
95		}
96	
97		IdString gate_type;
98		if (cell->type == ID($and))   gate_type = ID($_AND_);
99		if (cell->type == ID($or))    gate_type = ID($_OR_);
100		if (cell->type == ID($xor))   gate_type = ID($_XOR_);
101		if (cell->type == ID($xnor))  gate_type = ID($_XNOR_);
102		if (cell->type == ID($bweqx)) gate_type = ID($_XNOR_);
103		log_assert(!gate_type.empty());
104	
105		for (int i = 0; i < GetSize(sig_y); i++) {
106			RTLIL::Cell *gate = module->addCell(NEW_ID, gate_type);
107			transfer_src(gate, cell);
108			gate->setPort(ID::A, sig_a[i]);
109			gate->setPort(ID::B, sig_b[i]);
110			gate->setPort(ID::Y, sig_y[i]);
111		}
112	}
