114	void simplemap_reduce(RTLIL::Module *module, RTLIL::Cell *cell)
115	{
116		RTLIL::SigSpec sig_a = cell->getPort(ID::A);
117		RTLIL::SigSpec sig_y = cell->getPort(ID::Y);
118	
119		if (sig_y.size() == 0)
120			return;
121	
122		if (sig_a.size() == 0) {
123			if (cell->type == ID($reduce_and))  module->connect(RTLIL::SigSig(sig_y, RTLIL::SigSpec(1, sig_y.size())));
124			if (cell->type == ID($reduce_or))   module->connect(RTLIL::SigSig(sig_y, RTLIL::SigSpec(0, sig_y.size())));
125			if (cell->type == ID($reduce_xor))  module->connect(RTLIL::SigSig(sig_y, RTLIL::SigSpec(0, sig_y.size())));
126			if (cell->type == ID($reduce_xnor)) module->connect(RTLIL::SigSig(sig_y, RTLIL::SigSpec(1, sig_y.size())));
127			if (cell->type == ID($reduce_bool)) module->connect(RTLIL::SigSig(sig_y, RTLIL::SigSpec(0, sig_y.size())));
128			return;
129		}
130	
131		if (sig_y.size() > 1) {
132			module->connect(RTLIL::SigSig(sig_y.extract(1, sig_y.size()-1), RTLIL::SigSpec(0, sig_y.size()-1)));
133			sig_y = sig_y.extract(0, 1);
134		}
135	
136		IdString gate_type;
137		if (cell->type == ID($reduce_and))  gate_type = ID($_AND_);
138		if (cell->type == ID($reduce_or))   gate_type = ID($_OR_);
139		if (cell->type == ID($reduce_xor))  gate_type = ID($_XOR_);
140		if (cell->type == ID($reduce_xnor)) gate_type = ID($_XOR_);
141		if (cell->type == ID($reduce_bool)) gate_type = ID($_OR_);
142		log_assert(!gate_type.empty());
143	
144		RTLIL::Cell *last_output_cell = NULL;
145	
146		while (sig_a.size() > 1)
147		{
148			RTLIL::SigSpec sig_t = module->addWire(NEW_ID, sig_a.size() / 2);
149	
150			for (int i = 0; i < sig_a.size(); i += 2)
151			{
152				if (i+1 == sig_a.size()) {
153					sig_t.append(sig_a[i]);
154					continue;
155				}
156	
157				RTLIL::Cell *gate = module->addCell(NEW_ID, gate_type);
158				transfer_src(gate, cell);
159				gate->setPort(ID::A, sig_a[i]);
160				gate->setPort(ID::B, sig_a[i+1]);
161				gate->setPort(ID::Y, sig_t[i/2]);
162				last_output_cell = gate;
163			}
164	
165			sig_a = sig_t;
166		}
167	
168		if (cell->type == ID($reduce_xnor)) {
169			RTLIL::SigSpec sig_t = module->addWire(NEW_ID);
170			RTLIL::Cell *gate = module->addCell(NEW_ID, ID($_NOT_));
171			transfer_src(gate, cell);
172			gate->setPort(ID::A, sig_a);
173			gate->setPort(ID::Y, sig_t);
174			last_output_cell = gate;
175			sig_a = sig_t;
176		}
177	
178		if (last_output_cell == NULL) {
179			module->connect(RTLIL::SigSig(sig_y, sig_a));
180		} else {
181			last_output_cell->setPort(ID::Y, sig_y);
182		}
183	}
