185	static void logic_reduce(RTLIL::Module *module, RTLIL::SigSpec &sig, RTLIL::Cell *cell)
186	{
187		while (sig.size() > 1)
188		{
189			RTLIL::SigSpec sig_t = module->addWire(NEW_ID, sig.size() / 2);
190	
191			for (int i = 0; i < sig.size(); i += 2)
192			{
193				if (i+1 == sig.size()) {
194					sig_t.append(sig[i]);
195					continue;
196				}
197	
198				RTLIL::Cell *gate = module->addCell(NEW_ID, ID($_OR_));
199				transfer_src(gate, cell);
200				gate->setPort(ID::A, sig[i]);
201				gate->setPort(ID::B, sig[i+1]);
202				gate->setPort(ID::Y, sig_t[i/2]);
203			}
204	
205			sig = sig_t;
206		}
207	
208		if (sig.size() == 0)
209			sig = State::S0;
210	}
