263	void simplemap_eqne(RTLIL::Module *module, RTLIL::Cell *cell)
264	{
265		RTLIL::SigSpec sig_a = cell->getPort(ID::A);
266		RTLIL::SigSpec sig_b = cell->getPort(ID::B);
267		RTLIL::SigSpec sig_y = cell->getPort(ID::Y);
268		bool is_signed = cell->parameters.at(ID::A_SIGNED).as_bool();
269		bool is_ne = cell->type.in(ID($ne), ID($nex));
270	
271		RTLIL::SigSpec xor_out = module->addWire(NEW_ID, max(GetSize(sig_a), GetSize(sig_b)));
272		RTLIL::Cell *xor_cell = module->addXor(NEW_ID, sig_a, sig_b, xor_out, is_signed);
273		transfer_src(xor_cell, cell);
274		simplemap_bitop(module, xor_cell);
275		module->remove(xor_cell);
276	
277		RTLIL::SigSpec reduce_out = is_ne ? sig_y : module->addWire(NEW_ID);
278		RTLIL::Cell *reduce_cell = module->addReduceOr(NEW_ID, xor_out, reduce_out);
279		transfer_src(reduce_cell, cell);
280		simplemap_reduce(module, reduce_cell);
281		module->remove(reduce_cell);
282	
283		if (!is_ne) {
284			RTLIL::Cell *not_cell = module->addLogicNot(NEW_ID, reduce_out, sig_y);
285			transfer_src(not_cell, cell);
286			simplemap_lognot(module, not_cell);
287			module->remove(not_cell);
288		}
289	}
