339	void simplemap_bmux(RTLIL::Module *module, RTLIL::Cell *cell)
340	{
341		SigSpec sel = cell->getPort(ID::S);
342		SigSpec data = cell->getPort(ID::A);
343		int width = GetSize(cell->getPort(ID::Y));
344	
345		for (int idx = 0; idx < GetSize(sel); idx++) {
346			SigSpec new_data = module->addWire(NEW_ID, GetSize(data)/2);
347			for (int i = 0; i < GetSize(new_data); i += width) {
348				for (int k = 0; k < width; k++) {
349					RTLIL::Cell *gate = module->addCell(NEW_ID, ID($_MUX_));
350					transfer_src(gate, cell);
351					gate->setPort(ID::A, data[i*2+k]);
352					gate->setPort(ID::B, data[i*2+width+k]);
353					gate->setPort(ID::S, sel[idx]);
354					gate->setPort(ID::Y, new_data[i+k]);
355				}
356			}
357			data = new_data;
358		}
359	
360		module->connect(cell->getPort(ID::Y), data);
361	}
