363	void simplemap_lut(RTLIL::Module *module, RTLIL::Cell *cell)
364	{
365		SigSpec lut_ctrl = cell->getPort(ID::A);
366		SigSpec lut_data = cell->getParam(ID::LUT);
367		lut_data.extend_u0(1 << cell->getParam(ID::WIDTH).as_int());
368	
369		for (int idx = 0; GetSize(lut_data) > 1; idx++) {
370			SigSpec new_lut_data = module->addWire(NEW_ID, GetSize(lut_data)/2);
371			for (int i = 0; i < GetSize(lut_data); i += 2) {
372				RTLIL::Cell *gate = module->addCell(NEW_ID, ID($_MUX_));
373				transfer_src(gate, cell);
374				gate->setPort(ID::A, lut_data[i]);
375				gate->setPort(ID::B, lut_data[i+1]);
376				gate->setPort(ID::S, lut_ctrl[idx]);
377				gate->setPort(ID::Y, new_lut_data[i/2]);
378			}
379			lut_data = new_lut_data;
380		}
381	
382		module->connect(cell->getPort(ID::Y), lut_data);
383	}
