385	void simplemap_sop(RTLIL::Module *module, RTLIL::Cell *cell)
386	{
387		SigSpec ctrl = cell->getPort(ID::A);
388		SigSpec table = cell->getParam(ID::TABLE);
389	
390		int width = cell->getParam(ID::WIDTH).as_int();
391		int depth = cell->getParam(ID::DEPTH).as_int();
392		table.extend_u0(2 * width * depth);
393	
394		SigSpec products;
395	
396		for (int i = 0; i < depth; i++) {
397			SigSpec in, pat;
398			for (int j = 0; j < width; j++) {
399				if (table[2*i*width + 2*j + 0] == State::S1) {
400					in.append(ctrl[j]);
401					pat.append(State::S0);
402				}
403				if (table[2*i*width + 2*j + 1] == State::S1) {
404					in.append(ctrl[j]);
405					pat.append(State::S1);
406				}
407			}
408	
409			products.append(GetSize(in) > 0 ? module->Eq(NEW_ID, in, pat) : State::S1);
410		}
411	
412		module->connect(cell->getPort(ID::Y), module->ReduceOr(NEW_ID, products));
413	}
