431	void simplemap_ff(RTLIL::Module *, RTLIL::Cell *cell)
432	{
433		FfData ff(nullptr, cell);
434		for (int i = 0; i < ff.width; i++) {
435			FfData fff = ff.slice({i});
436			fff.is_fine = true;
