441	void simplemap_pmux(RTLIL::Module *module, RTLIL::Cell *cell)
442	{
443		RTLIL::SigSpec sig_a = cell->getPort(ID::A);
444		RTLIL::SigSpec sig_b = cell->getPort(ID::B);
445		RTLIL::SigSpec sig_s = cell->getPort(ID::S);
446		RTLIL::SigSpec sig_y = cell->getPort(ID::Y);
447	
448		int width = GetSize(sig_a);
449		int s_width = GetSize(sig_s);
450	
451		// Implement: |S
452		RTLIL::SigSpec any_s = sig_s;
453		logic_reduce(module, any_s, cell);
454	
455		for (int i = 0; i < width; i++) {
456			RTLIL::SigSpec b_and_bits;
457	
458			// Implement: B_AND_BITS = B_AND_S[WIDTH*j+i]
459			for (int j = 0; j < s_width; j++) {
460				RTLIL::Cell *and_gate = module->addCell(NEW_ID, ID($_AND_));
461				transfer_src(and_gate, cell);
462				and_gate->setPort(ID::A, sig_b[j * width + i]);
463				and_gate->setPort(ID::B, sig_s[j]);
464	
465				RTLIL::SigSpec and_y = module->addWire(NEW_ID, 1);
466				and_gate->setPort(ID::Y, and_y);
467				b_and_bits.append(and_y);
468			}
469	
470			// Implement: Y_B[i] = |B_AND_BITS
471			logic_reduce(module, b_and_bits, cell);
472	
473			// Implement: Y[i] = |S ? Y_B[i] : A[i]
474			RTLIL::Cell *mux_gate = module->addCell(NEW_ID, ID($_MUX_));
475			transfer_src(mux_gate, cell);
476			mux_gate->setPort(ID::A, sig_a[i]);
477			mux_gate->setPort(ID::B, b_and_bits);
478			mux_gate->setPort(ID::S, any_s);
479			mux_gate->setPort(ID::Y, sig_y[i]);
480		}
481	}
