483	void simplemap_get_mappers(dict<IdString, void(*)(RTLIL::Module*, RTLIL::Cell*)> &mappers)
484	{
485		mappers[ID($not)]         = simplemap_not;
486		mappers[ID($pos)]         = simplemap_pos;
487		mappers[ID($buf)]         = simplemap_buf;
488		mappers[ID($and)]         = simplemap_bitop;
489		mappers[ID($or)]          = simplemap_bitop;
490		mappers[ID($xor)]         = simplemap_bitop;
491		mappers[ID($xnor)]        = simplemap_bitop;
492		mappers[ID($bweqx)]       = simplemap_bitop;
493		mappers[ID($reduce_and)]  = simplemap_reduce;
494		mappers[ID($reduce_or)]   = simplemap_reduce;
495		mappers[ID($reduce_xor)]  = simplemap_reduce;
496		mappers[ID($reduce_xnor)] = simplemap_reduce;
497		mappers[ID($reduce_bool)] = simplemap_reduce;
498		mappers[ID($logic_not)]   = simplemap_lognot;
499		mappers[ID($logic_and)]   = simplemap_logbin;
500		mappers[ID($logic_or)]    = simplemap_logbin;
501		mappers[ID($eq)]          = simplemap_eqne;
502		mappers[ID($eqx)]         = simplemap_eqne;
503		mappers[ID($ne)]          = simplemap_eqne;
504		mappers[ID($nex)]         = simplemap_eqne;
505		mappers[ID($mux)]         = simplemap_mux;
506		mappers[ID($pmux)]        = simplemap_pmux;
507		mappers[ID($bwmux)]       = simplemap_bwmux;
508		mappers[ID($tribuf)]      = simplemap_tribuf;
509		mappers[ID($bmux)]        = simplemap_bmux;
510		mappers[ID($lut)]         = simplemap_lut;
511		mappers[ID($sop)]         = simplemap_sop;
512		mappers[ID($slice)]       = simplemap_slice;
513		mappers[ID($concat)]      = simplemap_concat;
514		mappers[ID($sr)]          = simplemap_ff;
515		mappers[ID($ff)]          = simplemap_ff;
516		mappers[ID($dff)]         = simplemap_ff;
517		mappers[ID($dffe)]        = simplemap_ff;
518		mappers[ID($dffsr)]       = simplemap_ff;
519		mappers[ID($dffsre)]      = simplemap_ff;
520		mappers[ID($adff)]        = simplemap_ff;
521		mappers[ID($sdff)]        = simplemap_ff;
522		mappers[ID($adffe)]       = simplemap_ff;
523		mappers[ID($sdffe)]       = simplemap_ff;
524		mappers[ID($sdffce)]      = simplemap_ff;
525		mappers[ID($aldff)]       = simplemap_ff;
526		mappers[ID($aldffe)]      = simplemap_ff;
527		mappers[ID($dlatch)]      = simplemap_ff;
528		mappers[ID($adlatch)]     = simplemap_ff;
529		mappers[ID($dlatchsr)]    = simplemap_ff;
530	}
531	
532	void simplemap(RTLIL::Module *module, RTLIL::Cell *cell)
533	{
534		static dict<IdString, void(*)(RTLIL::Module*, RTLIL::Cell*)> mappers;
535		static bool initialized_mappers = false;
536	
537		if (!initialized_mappers) {
538			simplemap_get_mappers(mappers);
539			initialized_mappers = true;
540		}
541	
542		mappers.at(cell->type)(module, cell);
543	}
544	
545	YOSYS_NAMESPACE_END
546	PRIVATE_NAMESPACE_BEGIN
547	
548	struct SimplemapPass : public Pass {
549		SimplemapPass() : Pass("simplemap", "mapping simple coarse-grain cells") { }
550		void help() override
551		{
552			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
553			log("\n");
554			log("    simplemap [selection]\n");
555			log("\n");
556			log("This pass maps a small selection of simple coarse-grain cells to yosys gate\n");
557			log("primitives. The following internal cell types are mapped by this pass:\n");
558			log("\n");
559			log("  $not, $pos, $and, $or, $xor, $xnor\n");
560			log("  $reduce_and, $reduce_or, $reduce_xor, $reduce_xnor, $reduce_bool\n");
561			log("  $logic_not, $logic_and, $logic_or, $mux, $pmux, $tribuf\n");
562			log("  $sr, $ff, $dff, $dffe, $dffsr, $dffsre, $adff, $adffe, $aldff, $aldffe, $sdff,\n");
563			log("  $sdffe, $sdffce, $dlatch, $adlatch, $dlatchsr\n");
564			log("\n");
565		}
566		void execute(std::vector<std::string> args, RTLIL::Design *design) override
567		{
568			log_header(design, "Executing SIMPLEMAP pass (map simple cells to gate primitives).\n");
569			extra_args(args, 1, design);
570	
571			dict<IdString, void(*)(RTLIL::Module*, RTLIL::Cell*)> mappers;
572			simplemap_get_mappers(mappers);
573	
574			for (auto mod : design->modules()) {
575				if (!design->selected(mod) || mod->get_blackbox_attribute())
576					continue;
577				std::vector<RTLIL::Cell*> cells = mod->cells();
578				for (auto cell : cells) {
579					if (mappers.count(cell->type) == 0)
580						continue;
581					if (!design->selected(mod, cell))
582						continue;
583					log("Mapping %s.%s (%s).\n", mod, cell, cell->type.unescape());
584					mappers.at(cell->type)(mod, cell);
585					mod->remove(cell);
586				}
587			}
588		}
589	} SimplemapPass;
590	
591	PRIVATE_NAMESPACE_END
