41	
42	void apply_prefix(IdString prefix, IdString &id)
43	{
44		if (id[0] == '\\')
45			id = stringf("%s.%s", prefix, id.c_str()+1);
46		else
47			id = stringf("$techmap%s.%s", prefix, id);
48	}
49	
50	void apply_prefix(IdString prefix, RTLIL::SigSpec &sig, RTLIL::Module *module)
51	{
52		vector<SigChunk> chunks = sig;
53		for (auto &chunk : chunks)
54			if (chunk.wire != nullptr) {
55				IdString wire_name = chunk.wire->name;
56				apply_prefix(prefix, wire_name);
57				log_assert(module->wire(wire_name) != nullptr);
58				chunk.wire = module->wire(wire_name);
59			}
60		sig = chunks;
61	}
62	
63	struct TechmapWorker
64	{
65		dict<IdString, void(*)(RTLIL::Module*, RTLIL::Cell*)> simplemap_mappers;
66		dict<std::pair<IdString, dict<IdString, RTLIL::Const>>, RTLIL::Module*> techmap_cache;
67		dict<RTLIL::Module*, bool> techmap_do_cache;
68		pool<RTLIL::Module*> module_queue;
69		dict<Module*, SigMap> sigmaps;
70	
71		pool<string> log_msg_cache;
72	
73		struct TechmapWireData {
74			RTLIL::Wire *wire;
75			RTLIL::SigSpec value;
76		};
77	
78		typedef dict<IdString, std::vector<TechmapWireData>> TechmapWires;
79	
80		bool extern_mode = false;
81		bool assert_mode = false;
82		bool recursive_mode = false;
83		bool autoproc_mode = false;
84		bool ignore_wb = false;
85	
86		std::string constmap_tpl_name(SigMap &sigmap, RTLIL::Module *tpl, RTLIL::Cell *cell, bool verbose)
87		{
88			std::string constmap_info;
89			dict<RTLIL::SigBit, std::pair<IdString, int>> connbits_map;
90	
91			for (auto &conn : cell->connections())
92				for (int i = 0; i < GetSize(conn.second); i++) {
93					RTLIL::SigBit bit = sigmap(conn.second[i]);
94					if (bit.wire == nullptr) {
95						if (verbose)
96							log("  Constant input on bit %d of port %s: %s\n", i, conn.first.unescape(), log_signal(bit));
97						constmap_info += stringf("|%s %d %d", conn.first.unescape(), i, bit.data);
98					} else if (connbits_map.count(bit)) {
99						if (verbose)
100							log("  Bit %d of port %s and bit %d of port %s are connected.\n", i, conn.first.unescape(),
101									connbits_map.at(bit).second, connbits_map.at(bit).first.unescape());
102						constmap_info += stringf("|%s %d %s %d", conn.first.unescape(), i,
103								connbits_map.at(bit).first.unescape(), connbits_map.at(bit).second);
104					} else {
105						connbits_map.emplace(bit, std::make_pair(conn.first, i));
106						constmap_info += stringf("|%s %d", conn.first.unescape(), i);
107					}
108				}
109	
110			return stringf("$paramod$constmap:%s%s", sha1(constmap_info), tpl->name);
111		}
112	
113		TechmapWires techmap_find_special_wires(RTLIL::Module *module)
114		{
115			TechmapWires result;
116	
117			if (module == nullptr)
118				return result;
119	
120			for (auto w : module->wires()) {
121				if (*w->name.c_str() == '$')
122					continue;
123	
124				if (w->name.contains("_TECHMAP_") && !w->name.contains("_TECHMAP_REPLACE_")) {
125					TechmapWireData record;
126					record.wire = w;
127					record.value = w;
128					result[w->name].push_back(record);
129					w->set_bool_attribute(ID::keep);
130					w->set_bool_attribute(ID::_techmap_special_);
131				}
132			}
133	
134			if (!result.empty()) {
135				SigMap sigmap(module);
136				for (auto &it1 : result)
137				for (auto &it2 : it1.second)
138					sigmap.apply(it2.value);
139			}
140	
141			return result;
142		}
143	
144		void techmap_module_worker(RTLIL::Design *design, RTLIL::Module *module, RTLIL::Cell *cell, RTLIL::Module *tpl)
145		{
146			if (tpl->processes.size() != 0) {
147				log("Technology map yielded processes:");
148				for (auto &it : tpl->processes)
149					log(" %s",it.first.unescape());
150				log("\n");
151				if (autoproc_mode) {
152					Pass::call_on_module(tpl->design, tpl, "proc");
153					log_assert(GetSize(tpl->processes) == 0);
154				} else
155					log_error("Technology map yielded processes -> this is not supported (use -autoproc to run 'proc' automatically).\n");
156			}
157	
158			std::string orig_cell_name;
159			pool<string> extra_src_attrs = cell->get_strpool_attribute(ID::src);
160	
161			orig_cell_name = cell->name.str();
162			for (auto tpl_cell : tpl->cells())
163				if (tpl_cell->name.ends_with("_TECHMAP_REPLACE_")) {
164					module->rename(cell, stringf("$techmap%d", autoidx++) + cell->name.str());
165					break;
166				}
167	
168			dict<IdString, IdString> memory_renames;
169	
170			for (auto &it : tpl->memories) {
171				IdString m_name = it.first;
172				apply_prefix(cell->name, m_name);
173				RTLIL::Memory *m = module->addMemory(m_name, it.second);
174				if (m->attributes.count(ID::src))
175					m->add_strpool_attribute(ID::src, extra_src_attrs);
176				memory_renames[it.first] = m->name;
177				design->select(module, m);
178			}
179	
180			dict<IdString, IdString> positional_ports;
181			dict<Wire*, IdString> temp_renamed_wires;
182			pool<SigBit> autopurge_tpl_bits;
183	
184			for (auto tpl_w : tpl->wires())
185			{
186				if (tpl_w->port_id > 0)
187				{
188					IdString posportname = stringf("$%d", tpl_w->port_id);
189					positional_ports.emplace(posportname, tpl_w->name);
190	
191					if (tpl_w->get_bool_attribute(ID::techmap_autopurge) &&
192							(!cell->hasPort(tpl_w->name) || !GetSize(cell->getPort(tpl_w->name))) &&
193							(!cell->hasPort(posportname) || !GetSize(cell->getPort(posportname))))
194					{
195						if (sigmaps.count(tpl) == 0)
196							sigmaps[tpl].set(tpl);
197	
198						for (auto bit : sigmaps.at(tpl)(tpl_w))
199							if (bit.wire != nullptr)
200								autopurge_tpl_bits.insert(bit);
201					}
202				}
203				IdString w_name = tpl_w->name;
204				apply_prefix(cell->name, w_name);
205				RTLIL::Wire *w = module->wire(w_name);
206				if (w != nullptr) {
207					temp_renamed_wires[w] = w->name;
208					module->rename(w, NEW_ID);
209					w = nullptr;
210				}
211				if (w == nullptr) {
212					w = module->addWire(w_name, tpl_w);
213					w->port_input = false;
214					w->port_output = false;
215					w->port_id = 0;
216					w->attributes.erase(ID::techmap_autopurge);
217					if (tpl_w->get_bool_attribute(ID::_techmap_special_))
218						w->attributes.clear();
219					if (w->attributes.count(ID::src))
220						w->add_strpool_attribute(ID::src, extra_src_attrs);
221				}
222				design->select(module, w);
223	
224				if (const char *p = strstr(tpl_w->name.c_str(), "_TECHMAP_REPLACE_.")) {
225					IdString replace_name = stringf("%s%s", orig_cell_name, p + strlen("_TECHMAP_REPLACE_"));
226					Wire *replace_w = module->addWire(replace_name, tpl_w);
227					module->connect(replace_w, w);
228				}
229			}
230	
231			pool<SigBit> tpl_written_bits;
232			for (auto tpl_cell : tpl->cells())
233			for (auto &conn : tpl_cell->connections())
234				if (tpl_cell->output(conn.first))
235					for (auto bit : conn.second)
236						tpl_written_bits.insert(bit);
237			for (auto &conn : tpl->connections())
238				for (auto bit : conn.first)
239					tpl_written_bits.insert(bit);
240	
241			SigMap port_signal_map;
242	
243			for (auto &it : cell->connections())
244			{
245				IdString portname = it.first;
246				if (positional_ports.count(portname) > 0)
247					portname = positional_ports.at(portname);
248				if (tpl->wire(portname) == nullptr || tpl->wire(portname)->port_id == 0) {
249					if (portname.begins_with("$"))
250						log_error("Can't map port `%s' of cell `%s' to template `%s'!\n", portname, cell->name, tpl->name);
251					continue;
252				}
253	
254				if (GetSize(it.second) == 0)
255					continue;
256	
257				RTLIL::Wire *w = tpl->wire(portname);
258				RTLIL::SigSig c, extra_connect;
259	
260				if (w->port_output && !w->port_input) {
261					c.first = it.second;
262					c.second = RTLIL::SigSpec(w);
263					apply_prefix(cell->name, c.second, module);
264					extra_connect.first = c.second;
265					extra_connect.second = c.first;
266				} else if (!w->port_output && w->port_input) {
267					c.first = RTLIL::SigSpec(w);
268					c.second = it.second;
269					apply_prefix(cell->name, c.first, module);
270					extra_connect.first = c.first;
271					extra_connect.second = c.second;
272				} else {
273					SigSpec sig_tpl = w, sig_tpl_pf = w, sig_mod = it.second;
274					apply_prefix(cell->name, sig_tpl_pf, module);
275					for (int i = 0; i < GetSize(sig_tpl) && i < GetSize(sig_mod); i++) {
276						if (tpl_written_bits.count(sig_tpl[i])) {
277							c.first.append(sig_mod[i]);
278							c.second.append(sig_tpl_pf[i]);
279						} else {
280							c.first.append(sig_tpl_pf[i]);
281							c.second.append(sig_mod[i]);
282						}
283					}
284					extra_connect.first = sig_tpl_pf;
285					extra_connect.second = sig_mod;
286				}
287	
288				if (c.second.size() > c.first.size())
289					c.second.remove(c.first.size(), c.second.size() - c.first.size());
290	
291				if (c.second.size() < c.first.size())
292					c.second.append(RTLIL::SigSpec(RTLIL::State::S0, c.first.size() - c.second.size()));
293	
294				log_assert(c.first.size() == c.second.size());
295	
296				// replace internal wires that are connected to external wires
297	
298				if (w->port_output && !w->port_input) {
299					port_signal_map.add(c.second, c.first);
300				} else
301				if (!w->port_output && w->port_input) {
302					port_signal_map.add(c.first, c.second);
303				} else {
304					module->connect(c);
305					extra_connect = SigSig();
306				}
307	
308				for (auto &attr : w->attributes) {
309					if (attr.first == ID::src)
310						continue;
311					auto lhs = GetSize(extra_connect.first);
312					auto rhs = GetSize(extra_connect.second);
313					if (lhs > rhs)
314						extra_connect.first.remove(rhs, lhs-rhs);
315					else if (rhs > lhs)
316						extra_connect.second.remove(lhs, rhs-lhs);
317					module->connect(extra_connect);
318					break;
319				}
320			}
321	
322			for (auto tpl_cell : tpl->cells())
323			{
324				IdString c_name = tpl_cell->name;
325				bool techmap_replace_cell = c_name.ends_with("_TECHMAP_REPLACE_");
326	
327				if (techmap_replace_cell)
328					c_name = orig_cell_name;
329				else if (const char *p = strstr(tpl_cell->name.c_str(), "_TECHMAP_REPLACE_."))
330					c_name = stringf("%s%s", orig_cell_name, p + strlen("_TECHMAP_REPLACE_"));
331				else
332					apply_prefix(cell->name, c_name);
333	
334				RTLIL::Cell *c = module->addCell(c_name, tpl_cell);
335				design->select(module, c);
336	
337				if (c->type == ID::_TECHMAP_PLACEHOLDER_ && tpl_cell->has_attribute(ID::techmap_chtype)) {
338					c->type = RTLIL::escape_id(tpl_cell->get_string_attribute(ID::techmap_chtype));
339					c->attributes.erase(ID::techmap_chtype);
340				}
341	
342				vector<IdString> autopurge_ports;
343	
344				for (auto &conn : c->connections())
345				{
346					bool autopurge = false;
347					if (!autopurge_tpl_bits.empty()) {
348						autopurge = GetSize(conn.second) != 0;
349						for (auto &bit : sigmaps.at(tpl)(conn.second))
350							if (!autopurge_tpl_bits.count(bit)) {
351								autopurge = false;
352								break;
353							}
354					}
355	
356					if (autopurge) {
357						autopurge_ports.push_back(conn.first);
358					} else {
359						RTLIL::SigSpec new_conn = conn.second;
360						apply_prefix(cell->name, new_conn, module);
361						port_signal_map.apply(new_conn);
362						c->setPort(conn.first, std::move(new_conn));
363					}
364				}
365	
366				for (auto &it2 : autopurge_ports)
367					c->unsetPort(it2);
368	
369				if (c->has_memid()) {
370					IdString memid = c->getParam(ID::MEMID).decode_string();
371					log_assert(memory_renames.count(memid) != 0);
372					c->setParam(ID::MEMID, Const(memory_renames[memid].str()));
373				} else if (c->is_mem_cell()) {
374					IdString memid = c->getParam(ID::MEMID).decode_string();
375					apply_prefix(cell->name, memid);
376					c->setParam(ID::MEMID, Const(memid.c_str()));
377				}
378	
379				if (c->attributes.count(ID::src))
380					c->add_strpool_attribute(ID::src, extra_src_attrs);
381	
382				if (techmap_replace_cell) {
383					for (auto attr : cell->attributes)
384						if (!c->attributes.count(attr.first))
385							c->attributes[attr.first] = attr.second;
386					c->attributes.erase(ID::reprocess_after);
387				}
388			}
389	
390			for (auto &it : tpl->connections()) {
391				RTLIL::SigSig c = it;
392				apply_prefix(cell->name.str(), c.first, module);
393				apply_prefix(cell->name.str(), c.second, module);
394				port_signal_map.apply(c.first);
395				port_signal_map.apply(c.second);
396				module->connect(c);
397			}
398	
399			module->remove(cell);
400	
401			for (auto &it : temp_renamed_wires)
402			{
403				Wire *w = it.first;
404				IdString name = it.second;
405				IdString altname = module->uniquify(name);
406				Wire *other_w = module->wire(name);
407				module->rename(other_w, altname);
408				module->rename(w, name);
409			}
410		}
411	
412		bool techmap_module(RTLIL::Design *design, RTLIL::Module *module, RTLIL::Design *map, pool<RTLIL::Cell*> &handled_cells,
413				const dict<IdString, pool<IdString>> &celltypeMap, bool in_recursion)
414		{
415			std::string mapmsg_prefix = in_recursion ? "Recursively mapping" : "Mapping";
416	
417			if (!design->selected(module) || module->get_blackbox_attribute(ignore_wb))
418				return false;
419	
420			bool log_continue = false;
421			bool did_something = false;
422			LogMakeDebugHdl mkdebug;
423	
424			SigMap sigmap(module);
425			FfInitVals initvals(&sigmap, module);
426	
427			TopoSort<RTLIL::Cell*, IdString::compare_ptr_by_name<RTLIL::Cell>> cells;
428			dict<RTLIL::Cell*, pool<RTLIL::SigBit>> cell_to_inbit;
429			dict<RTLIL::SigBit, pool<RTLIL::Cell*>> outbit_to_cell;
430	
431			for (auto cell : module->selected_cells())
432			{
433				if (handled_cells.count(cell) > 0)
434					continue;
435	
436				if (celltypeMap.count(cell->type) == 0) {
437					if (assert_mode && !cell->type.ends_with("_"))
438						log_error("(ASSERT MODE) No matching template cell for type %s found.\n", cell->type.unescape());
439					continue;
440				}
441	
442				for (auto &conn : cell->connections())
443				{
444					RTLIL::SigSpec sig = sigmap(conn.second);
445					sig.remove_const();
446	
447					if (GetSize(sig) == 0)
448						continue;
449	
450					for (auto &tpl_name : celltypeMap.at(cell->type)) {
451						RTLIL::Module *tpl = map->module(tpl_name);
452						RTLIL::Wire *port = tpl->wire(conn.first);
453						if (port && port->port_input)
454							cell_to_inbit[cell].insert(sig.begin(), sig.end());
455						if (port && port->port_output)
456							for (auto &bit : sig)
457								outbit_to_cell[bit].insert(cell);
458					}
459				}
460	
461				cells.node(cell);
462			}
463	
464			for (auto &it_right : cell_to_inbit)
465			for (auto &it_sigbit : it_right.second)
466			for (auto &it_left : outbit_to_cell[it_sigbit])
467				cells.edge(it_left, it_right.first);
468	
469			cells.sort();
470	
471			for (auto cell : cells.sorted)
472			{
473				log_assert(handled_cells.count(cell) == 0);
474				log_assert(cell == module->cell(cell->name));
475				bool mapped_cell = false;
476	
477				for (auto &tpl_name : celltypeMap.at(cell->type))
478				{
479					IdString derived_name = tpl_name;
480					RTLIL::Module *tpl = map->module(tpl_name);
481					dict<IdString, RTLIL::Const> parameters(cell->parameters);
482	
483					if (tpl->get_blackbox_attribute(ignore_wb))
484						continue;
485	
486					std::string extmapper_name;
487	
488					if (tpl->get_bool_attribute(ID::techmap_simplemap))
489						extmapper_name = "simplemap";
490	
491					if (tpl->get_bool_attribute(ID::techmap_maccmap))
492						extmapper_name = "maccmap";
493	
494					if (tpl->attributes.count(ID::techmap_wrap))
495						extmapper_name = "wrap";
496	
497					if (!extmapper_name.empty())
498					{
499						if ((extern_mode && !in_recursion) || extmapper_name == "wrap")
500						{
501							std::string m_name = stringf("$extern:%s:%s", extmapper_name, cell->type.unescape());
502	
503							for (auto &c : cell->parameters)
504								m_name += stringf(":%s=%s", c.first.unescape(), log_signal(c.second));
505	
506							if (extmapper_name == "wrap")
507								m_name += ":" + sha1(tpl->attributes.at(ID::techmap_wrap).decode_string());
508	
509							RTLIL::Design *extmapper_design = extern_mode && !in_recursion ? design : tpl->design;
510							RTLIL::Module *extmapper_module = extmapper_design->module(m_name);
511	
512							if (extmapper_module == nullptr)
513							{
514								extmapper_module = extmapper_design->addModule(m_name);
515								RTLIL::Cell *extmapper_cell = extmapper_module->addCell(cell->type, cell);
516	
517								extmapper_cell->set_src_attribute(cell->get_src_attribute());
518	
519								int port_counter = 1;
520								for (auto &c : extmapper_cell->connections_) {
521									RTLIL::Wire *w = extmapper_module->addWire(c.first, GetSize(c.second));
522									if (w->name.in(ID::Y, ID::Q))
523										w->port_output = true;
524									else
525										w->port_input = true;
526									w->port_id = port_counter++;
527									c.second = w;
528								}
529	
530								extmapper_module->fixup_ports();
531								extmapper_module->check();
532	
533								if (extmapper_name == "simplemap") {
534									log("Creating %s with simplemap.\n", extmapper_module);
535									if (simplemap_mappers.count(extmapper_cell->type) == 0)
536										log_error("No simplemap mapper for cell type %s found!\n", extmapper_cell->type.unescape());
537									simplemap_mappers.at(extmapper_cell->type)(extmapper_module, extmapper_cell);
538									extmapper_module->remove(extmapper_cell);
539								}
540	
541								if (extmapper_name == "maccmap") {
542									log("Creating %s with maccmap.\n", extmapper_module);
543									if (!extmapper_cell->type.in(ID($macc), ID($macc_v2)))
544										log_error("The maccmap mapper can only map $macc/$macc_v2 (not %s) cells!\n", extmapper_cell->type.unescape());
545									maccmap(extmapper_module, extmapper_cell);
546									extmapper_module->remove(extmapper_cell);
547								}
548	
549								if (extmapper_name == "wrap") {
550									std::string cmd_string = tpl->attributes.at(ID::techmap_wrap).decode_string();
551									log("Running \"%s\" on wrapper %s.\n", cmd_string, extmapper_module);
552									mkdebug.on();
553									Pass::call_on_module(extmapper_design, extmapper_module, cmd_string);
554									log_continue = true;
555								}
556							}
557	
558							cell->type = extmapper_module->name;
559							cell->parameters.clear();
560	
561							if (!extern_mode || in_recursion) {
562								tpl = extmapper_module;
563								goto use_wrapper_tpl;
564							}
565	
566							auto msg = stringf("Using extmapper %s for cells of type %s.", extmapper_module, cell->type.unescape());
567							if (!log_msg_cache.count(msg)) {
568								log_msg_cache.insert(msg);
569								log("%s\n", msg);
570							}
571							log_debug("%s %s.%s (%s) to %s.\n", mapmsg_prefix, module, cell, cell->type.unescape(), extmapper_module);
572						}
573						else
574						{
575							auto msg = stringf("Using extmapper %s for cells of type %s.", extmapper_name, cell->type.unescape());
576							if (!log_msg_cache.count(msg)) {
577								log_msg_cache.insert(msg);
578								log("%s\n", msg);
579							}
580							log_debug("%s %s.%s (%s) with %s.\n", mapmsg_prefix, module, cell, cell->type.unescape(), extmapper_name);
581	
582							if (extmapper_name == "simplemap") {
583								if (simplemap_mappers.count(cell->type) == 0)
584									log_error("No simplemap mapper for cell type %s found!\n", cell->type.unescape());
585								simplemap_mappers.at(cell->type)(module, cell);
586							}
587	
588							if (extmapper_name == "maccmap") {
589								if (!cell->type.in(ID($macc), ID($macc_v2)))
590									log_error("The maccmap mapper can only map $macc/$macc_v2 (not %s) cells!\n", cell->type.unescape());
591								maccmap(module, cell);
592							}
593	
594							module->remove(cell);
595							cell = nullptr;
596						}
597	
598						did_something = true;
599						mapped_cell = true;
600						break;
601					}
602	
603					for (auto &conn : cell->connections()) {
604						if (conn.first.begins_with("$"))
605							continue;
606						if (tpl->wire(conn.first) != nullptr && tpl->wire(conn.first)->port_id > 0)
607							continue;
608						if (!conn.second.is_fully_const() || parameters.count(conn.first) > 0 || tpl->avail_parameters.count(conn.first) == 0)
609							goto next_tpl;
610						parameters[conn.first] = conn.second.as_const();
611					}
612	
613					if (0) {
614			next_tpl:
615						continue;
616					}
617	
618					if (tpl->avail_parameters.count(ID::_TECHMAP_CELLTYPE_) != 0)
619						parameters.emplace(ID::_TECHMAP_CELLTYPE_, cell->type.unescape());
620					if (tpl->avail_parameters.count(ID::_TECHMAP_CELLNAME_) != 0)
621						parameters.emplace(ID::_TECHMAP_CELLNAME_, cell->name.unescape());
622	
623					for (auto &conn : cell->connections()) {
624						if (tpl->avail_parameters.count(stringf("\\_TECHMAP_CONSTMSK_%s_", conn.first.unescape())) != 0) {
625							std::vector<RTLIL::SigBit> v = sigmap(conn.second).to_sigbit_vector();
626							for (auto &bit : v)
627								bit = RTLIL::SigBit(bit.wire == nullptr ? RTLIL::State::S1 : RTLIL::State::S0);
628							parameters.emplace(stringf("\\_TECHMAP_CONSTMSK_%s_", conn.first.unescape()), RTLIL::SigSpec(v).as_const());
629						}
630						if (tpl->avail_parameters.count(stringf("\\_TECHMAP_CONSTVAL_%s_", conn.first.unescape())) != 0) {
631							std::vector<RTLIL::SigBit> v = sigmap(conn.second).to_sigbit_vector();
632							for (auto &bit : v)
633								if (bit.wire != nullptr)
634									bit = RTLIL::SigBit(RTLIL::State::Sx);
635							parameters.emplace(stringf("\\_TECHMAP_CONSTVAL_%s_", conn.first.unescape()), RTLIL::SigSpec(v).as_const());
636						}
637						if (tpl->avail_parameters.count(stringf("\\_TECHMAP_WIREINIT_%s_", conn.first.unescape())) != 0) {
638							parameters.emplace(stringf("\\_TECHMAP_WIREINIT_%s_", conn.first.unescape()), initvals(conn.second));
639						}
640					}
641	
642					{
643						int unique_bit_id_counter = 0;
644						dict<RTLIL::SigBit, int> unique_bit_id;
645						unique_bit_id[RTLIL::State::S0] = unique_bit_id_counter++;
646						unique_bit_id[RTLIL::State::S1] = unique_bit_id_counter++;
647						unique_bit_id[RTLIL::State::Sx] = unique_bit_id_counter++;
648						unique_bit_id[RTLIL::State::Sz] = unique_bit_id_counter++;
649	
650						for (auto &conn : cell->connections())
651							if (tpl->avail_parameters.count(stringf("\\_TECHMAP_CONNMAP_%s_", conn.first.unescape())) != 0) {
652								for (auto &bit : sigmap(conn.second))
653									if (unique_bit_id.count(bit) == 0)
654										unique_bit_id[bit] = unique_bit_id_counter++;
655							}
656	
657						// Find highest bit set
658						int bits = 0;
659						for (int i = 0; i < 32; i++)
660							if (((unique_bit_id_counter-1) & (1 << i)) != 0)
661								bits = i;
662						// Increment index by one to get number of bits
663						bits++;
664						if (tpl->avail_parameters.count(ID::_TECHMAP_BITS_CONNMAP_))
665							parameters[ID::_TECHMAP_BITS_CONNMAP_] = bits;
666	
667						for (auto &conn : cell->connections())
668							if (tpl->avail_parameters.count(stringf("\\_TECHMAP_CONNMAP_%s_", conn.first.unescape())) != 0) {
669								SigSpec sm = sigmap(conn.second);
670								RTLIL::Const::Builder builder(GetSize(sm) * bits);
671								for (auto &bit : sm) {
672									int val = unique_bit_id.at(bit);
673									for (int i = 0; i < bits; i++) {
674										builder.push_back((val & 1) != 0 ? State::S1 : State::S0);
675										val = val >> 1;
676									}
677								}
678								parameters.emplace(stringf("\\_TECHMAP_CONNMAP_%s_", conn.first.unescape()), builder.build());
679							}
680					}
681	
682					if (0) {
683				use_wrapper_tpl:;
684						// do not register techmap_wrap modules with techmap_cache
685					} else {
686						std::pair<IdString, dict<IdString, RTLIL::Const>> key(tpl_name, parameters);
687						auto it = techmap_cache.find(key);
688						if (it != techmap_cache.end()) {
689							tpl = it->second;
690						} else {
691							if (parameters.size() != 0) {
692								mkdebug.on();
693								derived_name = tpl->derive(map, parameters);
694								tpl = map->module(derived_name);
695								log_continue = true;
696							}
697							techmap_cache.emplace(std::move(key), tpl);
698						}
699					}
700	
701					RTLIL::Module *constmapped_tpl = map->module(constmap_tpl_name(sigmap, tpl, cell, false));
702					if (constmapped_tpl != nullptr)
703						tpl = constmapped_tpl;
704	
705					if (techmap_do_cache.count(tpl) == 0)
706					{
707						bool keep_running = true;
708						techmap_do_cache[tpl] = true;
709	
710						pool<IdString> techmap_wire_names;
711	
712						while (keep_running)
713						{
714							TechmapWires twd = techmap_find_special_wires(tpl);
715							keep_running = false;
716	
717							for (auto &it : twd)
718								techmap_wire_names.insert(it.first);
719	
720							for (auto &it : twd) {
721								if (!it.first.ends_with("_TECHMAP_FAIL_"))
722									continue;
723								for (const TechmapWireData &elem : it.second) {
724									RTLIL::SigSpec value = elem.value;
725									if (value.is_fully_const() && value.as_bool()) {
726										log("Not using module `%s' from techmap as it contains a %s marker wire with non-zero value %s.\n",
727												derived_name.c_str(), elem.wire->name.unescape(), log_signal(value));
728										techmap_do_cache[tpl] = false;
729									}
730								}
731							}
732	
733							if (!techmap_do_cache[tpl])
734								break;
735	
736							for (auto &it : twd)
737							{
738								if (!it.first.contains("_TECHMAP_DO_") || it.second.empty())
739									continue;
740	
741								auto &data = it.second.front();
742	
743								if (!data.value.is_fully_const())
744									log_error("Techmap yielded config wire %s with non-const value %s.\n", data.wire->name.unescape(), log_signal(data.value));
745	
746								techmap_wire_names.erase(it.first);
747	
748								const char *p = data.wire->name.c_str();
749								const char *q = strrchr(p+1, '.');
750								q = q ? q+1 : p+1;
751	
752								std::string cmd_string = data.value.as_const().decode_string();
753	
754							restart_eval_cmd_string:
755								if (cmd_string.rfind("CONSTMAP; ", 0) == 0)
756								{
757									cmd_string = cmd_string.substr(strlen("CONSTMAP; "));
758	
759									log("Analyzing pattern of constant bits for this cell:\n");
760									IdString new_tpl_name = constmap_tpl_name(sigmap, tpl, cell, true);
761									log("Creating constmapped module `%s'.\n", new_tpl_name.unescape());
762									log_assert(map->module(new_tpl_name) == nullptr);
763	
764									RTLIL::Module *new_tpl = map->addModule(new_tpl_name);
765									tpl->cloneInto(new_tpl);
766	
767									techmap_do_cache.erase(tpl);
768									techmap_do_cache[new_tpl] = true;
769									tpl = new_tpl;
770	
771									dict<RTLIL::SigBit, RTLIL::SigBit> port_new2old_map;
772									dict<RTLIL::SigBit, RTLIL::SigBit> port_connmap;
773									dict<RTLIL::SigBit, RTLIL::SigBit> cellbits_to_tplbits;
774	
775									for (auto wire : tpl->wires().to_vector())
776									{
777										if (!wire->port_input || wire->port_output)
778											continue;
779	
780										IdString port_name = wire->name;
781										tpl->rename(wire, NEW_ID);
782	
783										RTLIL::Wire *new_wire = tpl->addWire(port_name, wire);
784										wire->port_input = false;
785										wire->port_id = 0;
786	
787										for (int i = 0; i < wire->width; i++) {
788											port_new2old_map.emplace(RTLIL::SigBit(new_wire, i), RTLIL::SigBit(wire, i));
789											port_connmap.emplace(RTLIL::SigBit(wire, i), RTLIL::SigBit(new_wire, i));
790										}
791									}
792	
793									// Handle outputs first, as these cannot be remapped.
794									for (auto &conn : cell->connections())
795									{
796										Wire *twire = tpl->wire(conn.first);
797										if (!twire->port_output)
798											continue;
799	
800										for (int i = 0; i < GetSize(conn.second); i++) {
801											RTLIL::SigBit bit = sigmap(conn.second[i]);
802											RTLIL::SigBit tplbit(twire, i);
803											cellbits_to_tplbits[bit] = tplbit;
804										}
805									}
806	
807									// Now handle inputs, remapping as necessary.
808									for (auto &conn : cell->connections())
809									{
810										Wire *twire = tpl->wire(conn.first);
811										if (twire->port_output)
812											continue;
813	
814										for (int i = 0; i < GetSize(conn.second); i++)
815										{
816											RTLIL::SigBit bit = sigmap(conn.second[i]);
817											RTLIL::SigBit tplbit(twire, i);
818	
819											if (bit.wire == nullptr)
820											{
821												RTLIL::SigBit oldbit = port_new2old_map.at(tplbit);
822												port_connmap.at(oldbit) = bit;
823											}
824											else if (cellbits_to_tplbits.count(bit))
825											{
826												RTLIL::SigBit oldbit = port_new2old_map.at(tplbit);
827												port_connmap.at(oldbit) = cellbits_to_tplbits[bit];
828											}
829											else
830												cellbits_to_tplbits[bit] = tplbit;
831										}
832									}
833	
834									RTLIL::SigSig port_conn;
835									for (auto &it : port_connmap) {
836										port_conn.first.append(it.first);
837										port_conn.second.append(it.second);
838									}
839									tpl->connect(port_conn);
840	
841									tpl->check();
842									goto restart_eval_cmd_string;
843								}
844	
845								if (cmd_string.rfind("RECURSION; ", 0) == 0)
846								{
847									cmd_string = cmd_string.substr(strlen("RECURSION; "));
848									while (techmap_module(map, tpl, map, handled_cells, celltypeMap, true)) { }
849									goto restart_eval_cmd_string;
850								}
851	
852								Pass::call_on_module(map, tpl, cmd_string);
853	
854								log_assert(!strncmp(q, "_TECHMAP_DO_", 12));
855								std::string new_name = data.wire->name.substr(0, q-p) + "_TECHMAP_DONE_" + data.wire->name.substr(q-p+12);
856								while (tpl->wire(new_name) != nullptr)
857									new_name += "_";
858								tpl->rename(data.wire->name, new_name);
859	
860								keep_running = true;
861								break;
862							}
863						}
864	
865						TechmapWires twd = techmap_find_special_wires(tpl);
866						for (auto &it : twd) {
867							if (!it.first.ends_with("_TECHMAP_FAIL_") && (!it.first.begins_with("\\_TECHMAP_REMOVEINIT_") || !it.first.ends_with("_")) && !it.first.contains("_TECHMAP_DO_") && !it.first.contains("_TECHMAP_DONE_"))
868								log_error("Techmap yielded unknown config wire %s.\n", it.first.unescape());
869							if (techmap_do_cache[tpl])
870								for (auto &it2 : it.second)
871									if (!it2.value.is_fully_const())
872										log_error("Techmap yielded config wire %s with non-const value %s.\n", it2.wire->name.unescape(), log_signal(it2.value));
873							techmap_wire_names.erase(it.first);
874						}
875	
876						for (auto &it : techmap_wire_names)
877							log_error("Techmap special wire %s disappeared. This is considered a fatal error.\n", it.unescape());
878	
879						if (recursive_mode) {
880							if (log_continue) {
881								log_header(design, "Continuing TECHMAP pass.\n");
882								log_continue = false;
883								mkdebug.off();
884							}
885							while (techmap_module(map, tpl, map, handled_cells, celltypeMap, true)) { }
886						}
887					}
888	
889					if (techmap_do_cache.at(tpl) == false)
890						continue;
891	
892					if (log_continue) {
893						log_header(design, "Continuing TECHMAP pass.\n");
894						log_continue = false;
895						mkdebug.off();
896					}
897	
898					TechmapWires twd = techmap_find_special_wires(tpl);
899					for (auto &it : twd) {
900						if (it.first.begins_with("\\_TECHMAP_REMOVEINIT_")) {
901							for (auto &it2 : it.second) {
902								auto val = it2.value.as_const();
903								auto wirename = RTLIL::escape_id(it.first.substr(21, it.first.size() - 21 - 1));
904								auto it = cell->connections().find(wirename);
905								if (it != cell->connections().end()) {
906									auto sig = sigmap(it->second);
907									for (int i = 0; i < sig.size(); i++)
908										if (val[i] == State::S1)
909											initvals.remove_init(sig[i]);
910								}
911							}
912						}
913					}
914	
915					if (extern_mode && !in_recursion)
916					{
917						std::string m_name = stringf("$extern:%s", tpl);
918	
919						if (!design->module(m_name))
920						{
921							RTLIL::Module *m = design->addModule(m_name);
922							tpl->cloneInto(m);
923	
924							module_queue.insert(m);
925						}
926	
927						log_debug("%s %s.%s to imported %s.\n", mapmsg_prefix, module, cell, m_name);
928						cell->type = m_name;
929						cell->parameters.clear();
930					}
931					else
932					{
933						auto msg = stringf("Using template %s for cells of type %s.", tpl, cell->type.unescape());
934						if (!log_msg_cache.count(msg)) {
935							log_msg_cache.insert(msg);
936							log("%s\n", msg);
937						}
938						log_debug("%s %s.%s (%s) using %s.\n", mapmsg_prefix, module, cell, cell->type.unescape(), tpl);
939						techmap_module_worker(design, module, cell, tpl);
940						cell = nullptr;
941					}
942					did_something = true;
943					mapped_cell = true;
944					break;
945				}
946	
947				if (assert_mode && !mapped_cell)
948					log_error("(ASSERT MODE) Failed to map cell %s.%s (%s).\n", module, cell, cell->type.unescape());
949	
950				handled_cells.insert(cell);
951			}
952	
953			if (log_continue) {
954				log_header(design, "Continuing TECHMAP pass.\n");
955				log_continue = false;
956				mkdebug.off();
957			}
958	
959			return did_something;
960		}
961	};
962	
963	struct TechmapPass : public Pass {
964		TechmapPass() : Pass("techmap", "generic technology mapper") { }
965		void help() override
966		{
967			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
968			log("\n");
969			log("    techmap [-map filename] [selection]\n");
970			log("\n");
971			log("This pass implements a very simple technology mapper that replaces cells in\n");
972			log("the design with implementations given in form of a Verilog or RTLIL source\n");
973			log("file.\n");
974			log("\n");
975			log("    -map filename\n");
976			log("        the library of cell implementations to be used.\n");
977			log("        without this parameter a builtin library is used that\n");
978			log("        transforms the internal RTL cells to the internal gate\n");
979			log("        library.\n");
980			log("\n");
981			log("    -map %%<design-name>\n");
982			log("        like -map above, but with an in-memory design instead of a file.\n");
983			log("\n");
984			log("    -extern\n");
985			log("        load the cell implementations as separate modules into the design\n");
986			log("        instead of inlining them.\n");
987			log("\n");
988			log("    -max_iter <number>\n");
989			log("        only run the specified number of iterations on each module.\n");
990			log("        default: unlimited\n");
991			log("\n");
992			log("    -recursive\n");
993			log("        instead of the iterative breadth-first algorithm use a recursive\n");
994			log("        depth-first algorithm. both methods should yield equivalent results,\n");
995			log("        but may differ in performance.\n");
996			log("\n");
997			log("    -autoproc\n");
998			log("        Automatically call \"proc\" on implementations that contain processes.\n");
999			log("\n");
1000			log("    -wb\n");
1001			log("        Ignore the 'whitebox' attribute on cell implementations.\n");
1002			log("\n");
1003			log("    -assert\n");
1004			log("        this option will cause techmap to exit with an error if it can't map\n");
1005			log("        a selected cell. only cell types that end on an underscore are accepted\n");
1006			log("        as final cell types by this mode.\n");
1007			log("\n");
1008			log("    -D <define>, -I <incdir>\n");
1009			log("        this options are passed as-is to the Verilog frontend for loading the\n");
1010			log("        map file. Note that the Verilog frontend is also called with the\n");
1011			log("        '-nooverwrite' option set.\n");
1012			log("\n");
1013			log("    -dont_map <celltype>\n");
1014			log("        leave the given cell type unmapped by ignoring any mapping rules for it\n");
1015			log("\n");
1016			log("    -relativeshare\n");
1017			log("        use paths relative to share directory for source locations\n");
1018			log("        where possible (experimental).\n");
1019			log("\n");
1020			log("When a module in the map file has the 'techmap_celltype' attribute set, it will\n");
1021			log("match cells with a type that match the text value of this attribute. Otherwise\n");
1022			log("the module name will be used to match the cell.  Multiple space-separated cell\n");
1023			log("types can be listed, and wildcards using [] will be expanded (ie.\n");
1024			log("\"$_DFF_[PN]_\" is the same as \"$_DFF_P_ $_DFF_N_\").\n");
1025			log("\n");
1026			log("When a module in the map file has the 'techmap_simplemap' attribute set, techmap\n");
1027			log("will use 'simplemap' (see 'help simplemap') to map cells matching the module.\n");
1028			log("\n");
1029			log("When a module in the map file has the 'techmap_maccmap' attribute set, techmap\n");
1030			log("will use 'maccmap' (see 'help maccmap') to map cells matching the module.\n");
1031			log("\n");
1032			log("When a module in the map file has the 'techmap_wrap' attribute set, techmap\n");
1033			log("will create a wrapper for the cell and then run the command string that the\n");
1034			log("attribute is set to on the wrapper module.\n");
1035			log("\n");
1036			log("When a port on a module in the map file has the 'techmap_autopurge' attribute\n");
1037			log("set, and that port is not connected in the instantiation that is mapped, then\n");
1038			log("a cell port connected only to such wires will be omitted in the mapped version\n");
1039			log("of the circuit.\n");
1040			log("\n");
1041			log("All wires in the modules from the map file matching the pattern _TECHMAP_*\n");
1042			log("or *._TECHMAP_* are special wires that are used to pass instructions from\n");
1043			log("the mapping module to the techmap command. At the moment the following special\n");
1044			log("wires are supported:\n");
1045			log("\n");
1046			log("    _TECHMAP_FAIL_\n");
1047			log("        When this wire is set to a non-zero constant value, techmap will not\n");
1048			log("        use this module and instead try the next module with a matching\n");
1049			log("        'techmap_celltype' attribute.\n");
1050			log("\n");
1051			log("        When such a wire exists but does not have a constant value after all\n");
1052			log("        _TECHMAP_DO_* commands have been executed, an error is generated.\n");
1053			log("\n");
1054			log("    _TECHMAP_DO_*\n");
1055			log("        This wires are evaluated in alphabetical order. The constant text value\n");
1056			log("        of this wire is a yosys command (or sequence of commands) that is run\n");
1057			log("        by techmap on the module. A common use case is to run 'proc' on modules\n");
1058			log("        that are written using always-statements.\n");
1059			log("\n");
1060			log("        When such a wire has a non-constant value at the time it is to be\n");
1061			log("        evaluated, an error is produced. That means it is possible for such a\n");
1062			log("        wire to start out as non-constant and evaluate to a constant value\n");
1063			log("        during processing of other _TECHMAP_DO_* commands.\n");
1064			log("\n");
1065			log("        A _TECHMAP_DO_* command may start with the special token 'CONSTMAP; '.\n");
1066			log("        in this case techmap will create a copy for each distinct configuration\n");
1067			log("        of constant inputs and shorted inputs at this point and import the\n");
1068			log("        constant and connected bits into the map module. All further commands\n");
1069			log("        are executed in this copy. This is a very convenient way of creating\n");
1070			log("        optimized specializations of techmap modules without using the special\n");
1071			log("        parameters described below.\n");
1072			log("\n");
1073			log("        A _TECHMAP_DO_* command may start with the special token 'RECURSION; '.\n");
1074			log("        then techmap will recursively replace the cells in the module with their\n");
1075			log("        implementation. This is not affected by the -max_iter option.\n");
1076			log("\n");
1077			log("        It is possible to combine both prefixes to 'RECURSION; CONSTMAP; '.\n");
1078			log("\n");
1079			log("    _TECHMAP_REMOVEINIT_<port-name>_\n");
1080			log("        When this wire is set to a constant value, the init attribute of the\n");
1081			log("        wire(s) connected to this port will be consumed.  This wire must have\n");
1082			log("        the same width as the given port, and for every bit that is set to 1 in\n");
1083			log("        the value, the corresponding init attribute bit will be changed to 1'bx.\n");
1084			log("        If all bits of an init attribute are left as x, it will be removed.\n");
1085			log("\n");
1086			log("In addition to this special wires, techmap also supports special parameters in\n");
1087			log("modules in the map file:\n");
1088			log("\n");
1089			log("    _TECHMAP_CELLTYPE_\n");
1090			log("        When a parameter with this name exists, it will be set to the type name\n");
1091			log("        of the cell that matches the module.\n");
1092			log("\n");
1093			log("    _TECHMAP_CELLNAME_\n");
1094			log("        When a parameter with this name exists, it will be set to the name\n");
1095			log("        of the cell that matches the module.\n");
1096			log("\n");
1097			log("    _TECHMAP_CONSTMSK_<port-name>_\n");
1098			log("    _TECHMAP_CONSTVAL_<port-name>_\n");
1099			log("        When this pair of parameters is available in a module for a port, then\n");
1100			log("        former has a 1-bit for each constant input bit and the latter has the\n");
1101			log("        value for this bit. The unused bits of the latter are set to undef (x).\n");
1102			log("\n");
1103			log("    _TECHMAP_WIREINIT_<port-name>_\n");
1104			log("        When a parameter with this name exists, it will be set to the initial\n");
1105			log("        value of the wire(s) connected to the given port, as specified by the\n");
1106			log("        init attribute. If the attribute doesn't exist, x will be filled for the\n");
1107			log("        missing bits.  To remove the init attribute bits used, use the\n");
1108			log("        _TECHMAP_REMOVEINIT_*_ wires.\n");
1109			log("\n");
1110			log("    _TECHMAP_BITS_CONNMAP_\n");
1111			log("    _TECHMAP_CONNMAP_<port-name>_\n");
1112			log("        For an N-bit port, the _TECHMAP_CONNMAP_<port-name>_ parameter, if it\n");
1113			log("        exists, will be set to an N*_TECHMAP_BITS_CONNMAP_ bit vector containing\n");
1114			log("        N words (of _TECHMAP_BITS_CONNMAP_ bits each) that assign each single\n");
1115			log("        bit driver a unique id. The values 0-3 are reserved for 0, 1, x, and z.\n");
1116			log("        This can be used to detect shorted inputs.\n");
1117			log("\n");
1118			log("When a module in the map file has a parameter where the according cell in the\n");
1119			log("design has a port, the module from the map file is only used if the port in\n");
1120			log("the design is connected to a constant value. The parameter is then set to the\n");
1121			log("constant value.\n");
1122			log("\n");
1123			log("A cell with the name _TECHMAP_REPLACE_ in the map file will inherit the name\n");
1124			log("and attributes of the cell that is being replaced.\n");
1125			log("A cell with a name of the form `_TECHMAP_REPLACE_.<suffix>` in the map file will\n");
1126			log("be named thus but with the `_TECHMAP_REPLACE_' prefix substituted with the name\n");
1127			log("of the cell being replaced.\n");
1128			log("Similarly, a wire named in the form `_TECHMAP_REPLACE_.<suffix>` will cause a\n");
1129			log("new wire alias to be created and named as above but with the `_TECHMAP_REPLACE_'\n");
1130			log("prefix also substituted.\n");
1131			log("\n");
1132			log("A cell with the type _TECHMAP_PLACEHOLDER_ in the map file will have its type\n");
1133			log("changed to the content of the techmap_chtype attribute. This allows for choosing\n");
1134			log("the cell type dynamically.\n");
1135			log("\n");
1136			log("See 'help extract' for a pass that does the opposite thing.\n");
1137			log("\n");
1138			log("See 'help flatten' for a pass that does flatten the design (which is\n");
1139			log("essentially techmap but using the design itself as map library).\n");
1140			log("\n");
1141		}
1142		void execute(std::vector<std::string> args, RTLIL::Design *design) override
1143		{
1144			log_header(design, "Executing TECHMAP pass (map to technology primitives).\n");
1145			log_push();
1146	
1147			TechmapWorker worker;
1148			simplemap_get_mappers(worker.simplemap_mappers);
1149	
1150			std::vector<std::string> map_files;
1151			std::vector<RTLIL::IdString> dont_map;
1152			std::string verilog_frontend = "verilog -nooverwrite -noblackbox -icells";
1153			int max_iter = -1;
1154	
1155			size_t argidx;
1156			for (argidx = 1; argidx < args.size(); argidx++) {
1157				if (args[argidx] == "-map" && argidx+1 < args.size()) {
1158					map_files.push_back(args[++argidx]);
1159					continue;
1160				}
1161				if (args[argidx] == "-max_iter" && argidx+1 < args.size()) {
1162					max_iter = atoi(args[++argidx].c_str());
1163					continue;
1164				}
1165				if (args[argidx] == "-D" && argidx+1 < args.size()) {
1166					verilog_frontend += " -D " + args[++argidx];
1167					continue;
1168				}
1169				if (args[argidx] == "-I" && argidx+1 < args.size()) {
1170					verilog_frontend += " -I " + args[++argidx];
1171					continue;
1172				}
1173				if (args[argidx] == "-relativeshare") {
1174					verilog_frontend += " -relativeshare";
1175					log_experimental("techmap -relativeshare");
1176					continue;
1177				}
1178				if (args[argidx] == "-assert") {
1179					worker.assert_mode = true;
1180					continue;
1181				}
1182				if (args[argidx] == "-extern") {
1183					worker.extern_mode = true;
1184					continue;
1185				}
1186				if (args[argidx] == "-recursive") {
1187					worker.recursive_mode = true;
1188					continue;
1189				}
1190				if (args[argidx] == "-autoproc") {
1191					worker.autoproc_mode = true;
1192					continue;
1193				}
1194				if (args[argidx] == "-wb") {
1195					worker.ignore_wb = true;
1196					continue;
1197				}
1198				if (args[argidx] == "-dont_map" && argidx+1 < args.size()) {
1199					dont_map.push_back(RTLIL::escape_id(args[++argidx]));
1200					continue;
1201				}
1202				break;
1203			}
1204			extra_args(args, argidx, design);
1205	
1206			RTLIL::Design *map = new RTLIL::Design;
1207			if (map_files.empty()) {
1208				Frontend::frontend_call(map, nullptr, "+/techmap.v", verilog_frontend);
1209			} else {
1210				for (auto &fn : map_files)
1211					if (fn.compare(0, 1, "%") == 0) {
1212						if (!saved_designs.count(fn.substr(1))) {
1213							delete map;
1214							log_cmd_error("Can't open saved design `%s'.\n", fn.c_str()+1);
1215						}
1216						for (auto mod : saved_designs.at(fn.substr(1))->modules())
1217							if (!map->module(mod->name))
1218								map->add(mod->clone());
1219					} else {
1220						Frontend::frontend_call(map, nullptr, fn, (fn.size() > 3 && fn.compare(fn.size()-3, std::string::npos, ".il") == 0 ? "rtlil" : verilog_frontend));
1221					}
1222			}
1223	
1224			log_header(design, "Continuing TECHMAP pass.\n");
1225	
1226			dict<IdString, pool<IdString>> celltypeMap;
1227			for (auto module : map->modules()) {
1228				if (module->attributes.count(ID::techmap_celltype) && !module->attributes.at(ID::techmap_celltype).empty()) {
1229					char *p = strdup(module->attributes.at(ID::techmap_celltype).decode_string().c_str());
1230					for (char *q = strtok(p, " \t\r\n"); q; q = strtok(nullptr, " \t\r\n")) {
1231						std::vector<std::string> queue;
1232						queue.push_back(q);
1233						while (!queue.empty()) {
1234							std::string name = queue.back();
1235							queue.pop_back();
1236							auto pos = name.find('[');
1237							if (pos == std::string::npos) {
1238								// No further expansion.
1239								celltypeMap[RTLIL::escape_id(name)].insert(module->name);
1240							} else {
1241								// Expand [] in this name.
1242								auto epos = name.find(']', pos);
1243								if (epos == std::string::npos)
1244									log_error("Malformed techmap_celltype pattern %s\n", q);
1245								for (size_t i = pos + 1; i < epos; i++) {
1246									queue.push_back(name.substr(0, pos) + name[i] + name.substr(epos + 1, std::string::npos));
1247								}
1248							}
1249						}
1250					}
1251					free(p);
1252				} else {
1253					IdString module_name = module->name.begins_with("\\$") ?
1254							module->name.substr(1) : module->name.str();
1255					celltypeMap[module_name].insert(module->name);
1256				}
1257			}
1258	
1259			// Erase any rules disabled with a -dont_map argument
1260			for (auto type : dont_map)
1261				celltypeMap.erase(type);
1262	
1263			log_debug("Cell type mappings to use:\n");
1264			for (auto &i : celltypeMap) {
1265				i.second.sort(RTLIL::sort_by_id_str());
1266				std::string maps = "";
1267				for (auto &map : i.second)
1268					maps += stringf(" %s", map.unescape());
1269				log_debug("    %s:%s\n", i.first.unescape(), maps);
1270			}
1271			log_debug("\n");
1272	
1273			for (auto module : design->modules())
1274				worker.module_queue.insert(module);
1275	
1276			while (!worker.module_queue.empty())
1277			{
1278				RTLIL::Module *module = *worker.module_queue.begin();
1279				worker.module_queue.erase(module);
1280	
1281				int module_max_iter = max_iter;
1282				bool did_something = true;
1283				pool<RTLIL::Cell*> handled_cells;
1284				while (did_something) {
1285					did_something = false;
1286					if (worker.techmap_module(design, module, map, handled_cells, celltypeMap, false))
1287						did_something = true;
1288					if (did_something)
1289						module->check();
1290					if (module_max_iter > 0 && --module_max_iter == 0)
1291						break;
1292				}
1293			}
1294	
1295			log("No more expansions possible.\n");
1296			delete map;
1297	
1298			log_pop();
1299		}
1300	} TechmapPass;
1301	
1302	PRIVATE_NAMESPACE_END
