		std::string techmap_opts;
		if (!techmap_maps.empty())
			techmap_opts += " -map +/techmap.v";
		for (auto fn : techmap_maps)
			techmap_opts += stringf(" -map %s", fn);
		run(techmap_cmd + techmap_opts);
	}
